const name = 'Alice';
const score = 95;

// Old way
const msg1 = 'Hello, ' + name + '! Your score is ' + score + '%.';

// Template literal — cleaner
const msg2 = `Hello, ${name}! Your score is ${score}%.`;
console.log(msg2); // 'Hello, Alice! Your score is 95%.'

// Expressions inside ${}
const a = 10, b = 5;
console.log(`Sum: ${a + b}, Product: ${a * b}`); // 'Sum: 15, Product: 50'

// Multi-line string
const html = `
  <div class="card">
    <h2>${name}</h2>
    <p>Score: ${score}%</p>
  </div>
`;

// Tagged template (advanced)
function highlight(strings, ...values) {
  return strings.reduce((result, str, i) =>
    result + str + (values[i] !== undefined ? `<strong>${values[i]}</strong>` : ''), '');
}
const tagged = highlight`Hello ${name}, your score is ${score}%!`;
